command:
const KEY = "__holocronRollBridge";
if (globalThis[KEY]?.hookId != null) {
  Hooks.off("createChatMessage", globalThis[KEY].hookId);
  globalThis[KEY] = null;
  ui.notifications.info("📡 Pont de jets Holocron : DÉSACTIVÉ.");
} else {
  const handled = new Set();
  async function evalReq(msg) {
    try {
      const holo = msg?.flags?.holocron;
      const sf = msg?.flags?.starwarsffg;
      if (!holo?.req || !sf?.dicePool) return;
      if (!game.user.isGM) return;
      const token = String(holo.token || "");
      if (!token || handled.has(token)) return;
      handled.add(token);
      const Pool = globalThis.DicePoolFFG;
      const RollFFG = game.ffg?.RollFFG;
      if (!Pool || !RollFFG) { ui.notifications.error("Système FFG introuvable — jet Holocron non évalué."); return; }
      const dp = new Pool(sf.dicePool || {});
      const roll = new RollFFG(dp.renderDiceExpression(), {}, dp, holo.description || "");
      await roll.evaluate();
      const f = roll.ffg || {};
      const result = { success: f.success||0, failure: f.failure||0, advantage: f.advantage||0, threat: f.threat||0, triumph: f.triumph||0, despair: f.despair||0, light: f.light||0, dark: f.dark||0 };
      await roll.toMessage({ speaker: msg.speaker || {}, flavor: (holo.description || "Jet") + " — via Holocron", flags: { holocron: { resultFor: token, at: Date.now(), result } } });
      try { await msg.delete(); } catch (e) {}
    } catch (e) { console.error("[Holocron] pont de jets :", e); ui.notifications.warn("Pont de jets Holocron : échec (voir console)."); }
  }
  const hookId = Hooks.on("createChatMessage", evalReq);
  globalThis[KEY] = { hookId, handled };
  for (const m of game.messages.contents) { if (m?.flags?.holocron?.req) evalReq(m); }
  ui.notifications.info("📡 Pont de jets Holocron : ACTIF — les jets de l'Holocron seront lancés ici (" + game.user.name + ").");
}
